const PlayByPlayDescriptions = memo((props) => {

    const { type, players, found, game, period } = props;

    const getPlayerName = (players, jersey, team) => {
        return players.find(player => player.fields['Number'] === jersey && player.fields['Team ID'] === team)?.fields.Player ?? jersey;
    }
    return <div>
        {type === 'Fouls' ? `${getPlayerName(players, found?.p1, found.home == 'home' ? game.fields['Team A'] : game.fields['Team B'])} ${typename(found?.type ?? '')} Foul - ( ${found?.value ?? ''}PF ), committed against ${getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team B'] : game.fields['Team A'])}, ${found?.type2 ? `awarded ${found?.type2}` : ''}` :
            type === 'TOV' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} ${typename(found?.type ?? '')} turnover - ( ${found?.value ?? ''}TO )` :
                type === '3PTX' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} 3PT shot missed` :
                    type === '2PTX' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} 2PT shot missed` :
                        type === 'FTX' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} free throw missed` :
                            type === 'AIR' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} shot an air ball` :

                                type === '3PTM' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} 3PT ${found?.fast ? 'fastbreak' : ''} ${typename(found?.type ?? 'shot')} made - ( ${found?.value ?? ''}pts ) ${found?.p2 ? `Assisted by ${getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])}` : ''}` :
                                    type === '2PTM' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} 2PT ${found?.fast ? 'fastbreak' : ''} ${typename(found?.type ?? 'shot')} made - ( ${found?.value ?? ''}pts ) ${found?.p2 ? `Assisted by ${getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])}` : ''}` :
                                        type === 'FTM' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} free throw made - ( ${found?.value ?? ''}pts )` :
                                            type === 'INT' ? `Basket interference by - ${found?.team ?? 'xx'}` :
                                                type === 'TIME' ? `Timeout - ${found?.team ?? 'xx'}` :
                                                    type === 'MEDIA' ? `TV Timeout` :
                                                        type === 'DEAD' ? `Deadball Situation` :
                                                            type === 'START' ? `START OF ${period} PERIOD` :
                                                                type === 'END' ? `END OF ${period} PERIOD` :
                                                                    type === 'FINAL' ? `END OF ${period} PERIOD - FINAL ${found?.score}` :

                                                                        type === 'BLK' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} blocked the shot of ${getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team B'] : game.fields['Team A'])}- ( ${found?.value ?? ''}blk )` :
                                                                            type === 'AST' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} made the assist - ( ${found?.value ?? ''}ast )` :
                                                                                type === 'STL' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} stole the ball from ${getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team B'] : game.fields['Team A'])} - ( ${found?.value ?? ''}stl )` :
                                                                                    type === 'OREB' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} offensive rebound - ( ${found?.value ?? ''}rebs )` :
                                                                                        type === 'DREB' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} defensive rebound - ( ${found?.value ?? ''}rebs )` :

                                                                                            type === 'SUBOUT' ? `Substitution OUT - ${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])}` :
                                                                                                type === 'SUBIN' ? `Substitution IN - ${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} ` :
                                                                                                    type === 'FOULOUT' ? `Substitution OUT - ${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} FOULED OUT` :
                                                                                                        type === 'JUMP' ? `Jumpball - ${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} v ${getPlayerName(players, found?.p2, found?.team == 'away' ? game.fields['Team A'] : game.fields['Team B'])}, ${found?.type === 'jbw' ? getPlayerName(players, found?.p2, found?.team == 'away' ? game.fields['Team A'] : game.fields['Team B']) : getPlayerName(players, found?.p2, found?.team == 'home' ? game.fields['Team B'] : game.fields['Team A'])} wins tip` :
                                                                                                            type === 'TIP' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} tips ball out of bounds, side line inbound` :
                                                                                                                type === 'HELD' ? `${getPlayerName(players, found?.p1, found?.team == 'home' ? game.fields['Team A'] : game.fields['Team B'])} forces a held ball.` :
                                                                                                                    type === 'CHAL' ? `Coach challenge (${found?.team === 'home' ? game.fields['Team B'] : game.fields['Team B']})` :
                                                                                                                        type === 'DEL' ? `Delay of game warning (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} )` :
                                                                                                                            type === 'PEN' ? `Penalty Situation (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} )` :

                                                                                                                                type === 'WARN' ? `Warning issued (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} )` :
                                                                                                                                    type === 'CLK' ? `Shot clock violation (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} )` :
                                                                                                                                        type === 'TTECH2' ? `Technical Foul Type 2 (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} ) ${found?.type ? `${found?.type} awarded` : ''}` :
                                                                                                                                            type === 'TTECH1' ? `Technical Foul Type 1 (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} ) ${found?.type ? `${found?.type} awarded` : ''}` :
                                                                                                                                                type === 'CTECH2' ? `Technical Foul - Coach (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} ) ${found?.type ? `${found?.type} awarded` : ''}` :
                                                                                                                                                    type === 'CTECH1' ? `Technical Foul - Coach (${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} ) ${found?.type ? `${found?.type} awarded` : ''}` :
                                                                                                                                                        type === 'POS' ? `Change of possession - ${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} gets ball` :
                                                                                                                                                            type === 'OUTOPP' ? `Out of bounds - ${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} gets possession` :
                                                                                                                                                                type === 'OUTRET' ? `Out of bounds - ${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']} retains possession` :
                                                                                                                                                                    type === 'ARR' ? `Possession Arrow switches to ${found?.team === 'home' ? game.fields['Team A'] : game.fields['Team B']}` :
                                                                                                                                                                        type
        }
    </div>;
});

